SELECT algorithm_name, scene_name
FROM algorithms, scenes
WHERE algorithm_id = 1 AND scene_id = 1;

SELECT user_name
FROM users
WHERE user_id = 0;

SELECT a.algorithm_name, ap.average_recognition_rate
FROM algorithms a
JOIN algorithm_performance ap ON a.algorithm_id = ap.algorithm_id;

SELECT algorithms.author
FROM algorithms
JOIN algorithm_performance ON algorithms.algorithm_id = algorithm_performance.algorithm_id
WHERE algorithm_performance.average_memory_usage = (
    SELECT MAX(average_memory_usage) FROM algorithm_performance
);

SELECT algorithm_id, scene_id
FROM algorithm_scene_results
WHERE detection_rate > 0.8;

SELECT algorithms.algorithm_name, performance_metrics.recognition_rate
FROM algorithms
INNER JOIN performance_metrics ON algorithms.algorithm_id = performance_metrics.algorithm_id;

SELECT tag_name 
FROM algorithm_tags 
WHERE algorithm_id = 1;
